from flask import Flask, request, jsonify
import redis
import re

app = Flask(__name__)
r = redis.StrictRedis(host='localhost', port=6379, db=0)

# Allowlist of safe Redis commands
ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'KEYS', 'FLUSHDB'
}

def validate_command(command):
    # Check if the command is in the allowlist
    command_parts = command.split()
    return command_parts[0].upper() in ALLOWED_COMMANDS

@app.route('/execute', methods=['GET'])
def execute_command():
    command = request.args.get('command')
    
    if not command or not validate_command(command):
        return jsonify({'error': 'Invalid command'}), 400
    
    try:
        result = r.execute_command(command)
        return jsonify({'result': result}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=False)